/* Populate `h` with the baked valid (200,9) witness. Ready to pass to
 * check_equihash_solution() / domain_consensus_verify_equihash_solution(). */
static inline void verify_bench_fill_eh_header(struct block_header *h)
{
    block_header_init(h);
    h->nVersion = EHFX_NVERSION;
    memcpy(h->hashPrevBlock.data,        EHFX_HASHPREV,   32);
    memcpy(h->hashMerkleRoot.data,       EHFX_HASHMERKLE, 32);
    memcpy(h->hashFinalSaplingRoot.data, EHFX_HASHFINAL,  32);
    h->nTime  = EHFX_NTIME;
    h->nBits  = EHFX_NBITS;
    memcpy(h->nNonce.data, EHFX_NONCE, 32);
    memcpy(h->nSolution, EHFX_SOLUTION, sizeof(EHFX_SOLUTION));
    h->nSolutionSize = sizeof(EHFX_SOLUTION); /* 1344 -> (200,9) */
}

